import idautils, idc
for ea in idautils.Functions():
    for ref in idautils.CodeRefsFrom(ea, 0):
        name = idc.get_func_name(ref)
        if 'CreateFile' in name:
            result.setdefault('callers', []).append({'from': hex(ea), 'to': name})

import idautils, idc, ida_bytes
for ea in idautils.Functions():
    name = idc.get_func_name(ea)
    if name.startswith('sub_'):
        for ref in idautils.DataRefsFrom(ea):
            s = idc.get_strlit_contents(ref)
            if s:
                idc.set_name(ea, f'uses_{s[:20].decode()}')
                break

import idautils
imports = {}
def cb(ea, name, ordinal):
    imports.setdefault(current_dll, []).append(name or f'ord_{ordinal}')
    return True
for i in range(idaapi.get_import_module_qty()):
    current_dll = idaapi.get_import_module_name(i)
    idaapi.enum_import_names(i, cb)
result['imports'] = imports
